        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        val p = node.treeParent
        if (
            // check
            // `{ p -> ... }`
            // and
            // `when { m -> ... }`
            // only
            p.elementType.let { it != FUNCTION_LITERAL && it != WHEN_ENTRY } ||
            // For a function literal, only insert a newline after the arrow when the value parameter list has
            // multiple parameters which are on different lines. This should not be done when only the body of the
            // lambda expression is a multiline expression. In the latter case, the lambda expression is reformatted
            // by other functions.
            (p.elementType == FUNCTION_LITERAL && p.findChildByType(VALUE_PARAMETER_LIST)?.textContains('\n') != true) ||
            // For a when entry, only insert a newline after the arrow when the expression following the arrow spans
            // multiple lines
            (p.elementType == WHEN_ENTRY && !p.textContains('\n')) ||
            // permit
            // when {
            //     m -> 0 + d({
            //     })
            // }
            (p.elementType == WHEN_ENTRY && mustBeFollowedByNewline(node)) ||
            // permit
            // when (this) {
            //     in 0x1F600..0x1F64F, // Emoticons
            //     0x200D // Zero-width Joiner
            //     -> true
            // }
            (p.elementType == WHEN_ENTRY && node.prevLeaf()?.textContains('\n') == true)
